const TT = (moduleId, id, num, name, slug, tags, hookQ, hookI, blocks, rel, gaps, diff, svgStr, vaType) => ({
  trackKey: TRACK_KEY, moduleId, topicId: id, topicNumber: num, name, slug,
  metadata: { estimated_minutes: 50, difficulty: 4, prerequisites: [], tags },
  hook: { question: hookQ, insight: hookI },
  teaching: { blocks, visual_aid: { type: vaType, svg: svgStr, alt_text: `${name} architecture diagram.` } },
  interviewRelevance: rel, commonGaps: { gaps },
  prerequisites: [], estimatedMinutes: 50, difficulty: diff, xpReward: 80, visualizer: null,
});
const C = (section, heading, body) => ({ kind: "concept", section, heading, body });
const K = (section, heading, body) => ({ kind: "code", section, heading, body });
const G = (id, w, r, d) => ({ gap_id: id, what_students_get_wrong: w, remediation: r, detection_pattern: d });

const TOPICS = [
  // ────────────────────────── SERVICE DISCOVERY ────────────────────────────
  TT("sysd_m17", "sysd_m17_t1", 1, "Design a Service Discovery System", "design-service-discovery",
    ["case-study", "service-discovery", "registry", "health"],
    "In a microservices world, service instances are constantly created, destroyed, autoscaled, and moved — so their network addresses change all the time. Hardcoding IPs is impossible. How does service A find a healthy instance of service B right now?",
    "A SERVICE REGISTRY holds the live map of service -> healthy instance addresses. Instances REGISTER themselves on startup and send HEARTBEATS; HEALTH CHECKS evict dead ones. Consumers DISCOVER instances by querying the registry (client-side discovery) or via a load balancer that does (server-side). The registry is the critical component — usually a consistent store (etcd/Consul/ZooKeeper). Dynamic registration + health-based eviction + lookup is the substance.",
    [
      C("requirements", "Requirements",
        "Functional: let services find the current network locations of other services; register instances as they come up and remove them as they go down/fail; return only HEALTHY instances; support load balancing across them. Non-functional: the registry data must be reasonably UP-TO-DATE (a dead instance should stop being returned quickly), lookups must be low-latency (they're on the call path) and highly available (if discovery is down, services can't find each other), and it must scale to many services/instances. Clarify scope: dynamic environments (microservices/containers/autoscaling) where instances are ephemeral. The defining problem is that instance addresses are DYNAMIC — containers restart with new IPs, autoscaling adds/removes instances, failures happen — so a static config or hardcoded IPs can't work; you need a live, self-updating directory of where each service's healthy instances are, plus a way to detect and remove instances that have died so callers don't route to them."),
      K("estimation", "Capacity estimation (with numbers)",
        "Assume 1000 services, ~10 instances each -> ~10k registered instances.\n  registration churn: autoscaling/deploys -> hundreds of register/deregister/min\n  heartbeats: 10k instances * 1 every ~10s -> ~1k heartbeats/sec\n  lookups: on the call path (often cached at clients) -> high, but cacheable\nRegistry data is small (service -> [addr, health]) -> fits in memory, replicated.\nTakeaway: it's a small but CRITICAL dataset with high read/heartbeat rate ->\nreplicate for HA (often a consensus store), cache lookups, evict via health/TTL."),
      C("hld", "High-level design",
        "A SERVICE REGISTRY is the source of truth mapping each service name to its set of currently-healthy instances (address + metadata). On startup, an instance REGISTERS itself (self-registration) — or a third-party registrar registers it — and then sends periodic HEARTBEATS (or the registry actively health-checks it); if heartbeats stop or a health check fails, the registry removes the instance so it's no longer returned. A consumer DISCOVERS instances either CLIENT-SIDE (it queries the registry, gets the instance list, and load-balances itself) or SERVER-SIDE (it calls through a load balancer/router that consults the registry and forwards). The registry itself is replicated for availability, often built on a CONSISTENT store (etcd/Consul/ZooKeeper) so all consumers see a coherent view. Trace a call: Service B instance starts -> registers + heartbeats -> Service A needs B -> looks up B in the registry -> gets healthy instances -> load-balances a request to one. The registry + registration + health checking + lookup loop keeps routing correct as instances churn."),
      K("api", "API design",
        "register(service, instanceId, addr, metadata) -> lease/ttl\nheartbeat(service, instanceId)            // renew lease; stop -> evicted\nderegister(service, instanceId)           // graceful shutdown\ndiscover(service) -> [ { addr, healthy, metadata } ]   // healthy instances\n  client-side: caller load-balances; server-side: an LB/proxy does it\nDNS-based variant: resolve service-name -> current instance IPs"),
      K("data_model", "Data model",
        "registry:  service_name -> [ { instance_id, addr, status(up|down), lease_expiry, meta } ]\nlease/ttl: each instance has a heartbeat lease; missed heartbeats -> evicted\nhealth:    health-check result per instance (active probe or heartbeat-based)\nstore:     replicated, often a CP consensus store (etcd/Consul/ZooKeeper)\nclient cache: consumers cache the instance list (refreshed) to avoid per-call lookups"),
      C("deep_dive", "Deep dive: registration & health checking",
        "Keeping the registry accurate as instances churn is the core job. REGISTRATION: in SELF-registration, each instance registers itself with the registry on startup and deregisters on graceful shutdown; in THIRD-PARTY registration, a separate registrar (or the orchestrator, e.g. Kubernetes) watches instances and updates the registry — decoupling services from registry logic. HEALTH CHECKING is what prevents routing to dead instances: either the instance sends periodic HEARTBEATS and the registry evicts it when they stop (a lease/TTL that must be renewed), or the registry actively PROBES each instance's health endpoint and removes failing ones. The subtlety is timing: too-aggressive eviction removes instances during transient blips (flapping); too-lazy eviction keeps routing to dead instances (failed requests). So health/heartbeat intervals and failure thresholds are tuned to balance freshness against stability, and the data is eventually consistent (a just-died instance may briefly still be returned, so clients also need retries/circuit-breaking)."),
      C("deep_dive", "Deep dive: client-side vs server-side discovery & the registry",
        "There are two discovery patterns. CLIENT-SIDE discovery: the caller queries the registry, gets the list of healthy instances, and performs LOAD BALANCING itself (picks one) — efficient (no extra hop) and the client controls the LB strategy, but every client must implement discovery logic (per-language). SERVER-SIDE discovery: the caller sends the request to a LOAD BALANCER / router (or via DNS) that consults the registry and forwards to an instance — clients stay simple (just call a stable endpoint) at the cost of an extra hop and running that LB tier (this is essentially what a Kubernetes Service or an API gateway does). DNS-based discovery is a common server-side flavor (resolve a service name to current IPs), simple but with DNS caching/TTL staleness caveats. Underpinning both is the REGISTRY, which must be highly available and consistent — hence it's typically a CONSENSUS store (etcd/Consul/ZooKeeper) that replicates the registration data so all consumers see a coherent, current view; in container platforms the orchestrator's control plane plays this role. The registry's availability and freshness are the whole system's foundation."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "The registry is the critical dependency / potential SPOF — if it's unavailable, services can't discover each other — so it's replicated (a consensus cluster) and clients CACHE the instance list so a brief registry outage doesn't immediately break calls (they use the last-known-good list). STALENESS is the core tension: registry data is eventually consistent, so a just-died instance may still be returned briefly — mitigate with health checks + client-side retries/circuit breaking, and tune heartbeat/eviction timing (freshness vs flapping). High heartbeat/lookup volume is handled by caching and efficient stores. Trade-offs: client-side discovery (no extra hop, client controls LB, but per-language logic) vs server-side (simple clients, extra hop + LB tier); aggressive eviction (fresh, risks flapping out healthy instances) vs lazy (stable, routes to dead longer); CP registry (consistent view, may be unavailable in a partition) vs AP (always answers, possibly stale). Closing signal: a replicated registry (consensus store) with self/health-checked registration, client-cached lookups, and retries to tolerate brief staleness."),
      C("deep_dive", "Deep dive: consistency, caching & operations",
        "Operationally the registry must stay available and approximately fresh. Consistency model: a CP registry (etcd/ZooKeeper, consensus-based) gives every consumer a coherent view and is the common choice, but during a network partition it may refuse writes/reads on the minority side (favoring correctness); an AP registry (like older Eureka) always answers, accepting some staleness for availability — pick per how bad stale routing is. Client caching: consumers cache the discovered instance list and refresh it periodically (and on errors), so most calls don't hit the registry and a registry blip doesn't immediately break routing — the cache is the resilience layer. Integration with orchestrators: in Kubernetes the platform IS the discovery system (the API server holds endpoints, kube-proxy/DNS route to them), so 'service discovery' is often provided rather than built — know how it maps. Graceful deregistration on deploys avoids brief routing to terminating instances (drain + deregister before kill). Metadata-based routing: the registry can carry instance metadata (version, zone) for canary or zone-aware load balancing. Observability: registration churn, lookup latency, stale-entry rate, and registry availability are the SLOs. The spine holds: a replicated registry, health-checked dynamic registration, cached client lookups, and retries to absorb the inherent staleness."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'How do services find each other when IPs change?' a registry of service -> healthy instances, kept current by registration + health checks. 'How are dead instances removed?' heartbeats/leases (evict on miss) or active health probes; tune timing vs flapping. 'Client-side vs server-side discovery?' client queries+LBs itself (no hop, per-language) vs an LB/DNS does it (simple clients, extra hop). 'Registry down?' replicate it (consensus store) and have clients cache instance lists + retry. 'CP or AP registry?' CP (consistent, may be unavailable in a partition) vs AP (always answers, stale) — pick per tolerance. 'In Kubernetes?' the platform provides discovery (endpoints + DNS) — often you don't build it. 'Stale instance still returned?' eventual consistency -> client retries/circuit breaking. Each returns to the spine: a replicated registry with health-checked registration, cached lookups, and retries to tolerate staleness."),
    ],
    "Service discovery tests a live registry of service -> healthy instances kept current by registration + health checks, lookup via client-side (caller LBs) or server-side (LB/DNS) discovery, a replicated/consensus registry as the critical component, and client caching + retries to tolerate eventual-consistency staleness. The signal is dynamic registration + health-based eviction, not static config.",
    [
      G("static_config", "Hardcoding instance addresses / static config in a dynamic environment.", "Use a registry instances register with + health checks; discover dynamically.", "Service addresses are configured/hardcoded, not discovered."),
      G("no_health", "A registry with no health checking, returning dead instances.", "Add heartbeats/leases or active health probes to evict failed instances.", "Instances stay registered after they die; callers hit dead nodes."),
      G("registry_spof", "A single registry with no HA and no client caching.", "Replicate the registry (consensus store) and cache lookups at clients + retry.", "One registry; an outage breaks all discovery; no client cache."),
    ],
    0.6, DIAG.discovery, "Service discovery architecture"),

  // ─────────────────────────────── SCHEMA REGISTRY ─────────────────────────
  TT("sysd_m17", "sysd_m17_t2", 2, "Design a Schema Registry", "design-schema-registry",
    ["case-study", "schema-registry", "evolution", "kafka"],
    "Hundreds of services produce and consume events on shared topics. A producer adds a field to its event format — and consumers that deploy on a different schedule break, or worse, silently misread data. How do producers and consumers agree on message structure as it evolves independently?",
    "A central SCHEMA REGISTRY stores versioned schemas per subject and enforces COMPATIBILITY rules when a new version is registered, so producers and consumers (which deploy independently) never break each other. Messages carry a small SCHEMA ID instead of the full schema; consumers fetch the schema by id (cached) to deserialize. Compatible evolution + id-based serialization are the substance — it's the contract layer for event-driven systems.",
    [
      C("requirements", "Requirements",
        "Functional: store and version message/event SCHEMAS (e.g. Avro/Protobuf/JSON Schema) under named subjects (usually per topic); let producers register a schema and get an id; let consumers fetch a schema by id to deserialize; and ENFORCE compatibility when a new schema version is registered. Non-functional: it's a central source of truth that must be highly available (it's needed to serialize/deserialize), low-latency (lookups on the data path, but cacheable), and must guarantee that schema EVOLUTION doesn't break running producers/consumers. Clarify scope: the contract layer for event-driven/streaming systems (Kafka + Avro is the canonical case). The defining problem is INDEPENDENT DEPLOYMENT: in a large system, the producer of an event and its many consumers are different teams deploying on different schedules, so when the event format changes, you can't update everyone atomically — without enforced compatibility, a change silently breaks consumers (deserialization errors or, worse, misread fields). The registry makes the message format an explicit, versioned, compatibility-checked contract."),
      K("estimation", "Capacity estimation (with numbers)",
        "Schemas are few and slow-changing: hundreds of subjects, a handful of versions each\n  -> the registry's DATA is tiny (KBs-MBs) and rarely written.\nBUT serialize/deserialize happens on EVERY message: millions/sec\n  -> clients CACHE schemas locally (fetch by id once) so the registry isn't on\n     the per-message path; lookups are rare (cache miss / new id).\nThe registry must be HA (if a consumer can't resolve a new schema id, it can't decode).\nTakeaway: tiny, read-mostly, heavily-cached metadata service whose value is\ncorrectness (compatibility) and availability, not throughput."),
      C("hld", "High-level design",
        "A central SCHEMA REGISTRY stores schemas organized by SUBJECT (e.g. a topic), each with an ordered list of VERSIONS, and assigns every unique schema a global SCHEMA ID. When a PRODUCER wants to send messages, it registers (or looks up) its schema and gets the id; it then SERIALIZES each message and prepends the small schema id (not the whole schema) to the payload. A CONSUMER reading a message extracts the schema id, fetches the corresponding schema FROM THE REGISTRY (cached after first fetch), and uses it to DESERIALIZE — so producer and consumer agree on structure via the registry, not by hardcoding. When a producer registers a NEW version of a subject's schema, the registry runs a COMPATIBILITY CHECK against existing versions and rejects the change if it would break consumers (or producers). Trace it: producer registers schema v2 -> registry checks it's backward-compatible -> returns id 42 -> messages carry id 42 -> consumer sees id 42, fetches+caches schema 42, deserializes. The registry is the contract authority; clients cache aggressively so it's off the hot path."),
      K("api", "API design",
        "POST /subjects/{subject}/versions { schema } -> { id }   // register (compat-checked)\nGET  /schemas/ids/{id}            -> { schema }            // resolve (clients cache)\nGET  /subjects/{subject}/versions/latest -> { id, version, schema }\nPOST /compatibility/subjects/{subject}/versions/latest { schema } -> { is_compatible }\nMessage wire format: [magic byte][4-byte schema id][serialized payload]"),
      K("data_model", "Data model",
        "subjects:  subject -> ordered [ version ]   (usually one subject per topic)\nschemas:   schema_id PK -> schema definition (Avro/Protobuf/JSON), hash\nversions:  (subject, version) -> schema_id\ncompat:    per-subject compatibility policy (backward | forward | full | none)\nclient cache: schema_id -> schema (so deserialization doesn't hit the registry)"),
      C("deep_dive", "Deep dive: schema evolution & compatibility",
        "The registry's core value is enforcing COMPATIBLE evolution so independently-deployed producers/consumers don't break. The compatibility modes: BACKWARD compatible — new schema can read data written with the OLD schema (so consumers can upgrade first; achieved by only adding optional/defaulted fields or removing fields) — the most common default. FORWARD compatible — old schema can read data written with the NEW schema (so producers can upgrade first; add fields old readers ignore). FULL — both. NONE — no checks. The point of these rules is to handle the independent-deployment reality: with BACKWARD compatibility, a producer can roll out a new schema and old consumers still work until they upgrade; with FORWARD, new producers don't break old consumers. The registry checks a proposed new version against the relevant existing version(s) per the subject's policy and REJECTS incompatible changes at registration time — turning 'someone changed the event and broke prod at 3am' into a clear, early CI/deploy-time error. Understanding which changes are safe (add optional field = backward-compatible; rename/remove-required = breaking) is the heart of the topic."),
      C("deep_dive", "Deep dive: id-based serialization & decoupling",
        "The second key idea is putting only a SCHEMA ID in each message, not the whole schema. If every message embedded its full schema, that would be huge overhead on high-volume streams; instead the producer registers the schema once, and each message carries just a compact id (e.g. 4 bytes) pointing to it. Consumers, on seeing an id, fetch the schema from the registry ONCE and CACHE it, so subsequent messages with that id deserialize from the cached schema with no registry call — keeping the registry entirely off the per-message hot path (critical at millions of messages/sec). This DECOUPLES the payload from the schema definition and lets schemas evolve (new ids for new versions) without changing the wire mechanics. It also means the registry must be available when a consumer first encounters a new id (or it can't decode) — hence HA + client caching. This id-indirection (small id on the wire + cached resolution) is what makes schema management efficient at scale, and pairs with compatibility checks to give safe, low-overhead evolution."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "Availability is critical: if a consumer hits a NEW schema id it hasn't cached and the registry is unreachable, it can't deserialize that message — so the registry must be HA (replicated) and clients should cache aggressively and pre-warm where possible. Compatibility policy is a trade: strict (FULL) compatibility is safest but most constraining on how schemas can change; loose (NONE) is flexible but lets breaking changes through — pick per how independently producers/consumers deploy. A bad/over-permissive policy can still let a breaking change ship. Caching staleness is minimal (schemas are immutable per id) so it's safe to cache forever. Trade-offs: backward compat (consumers upgrade first, common) vs forward (producers first) vs full (both, most constrained); id-on-the-wire + registry fetch (tiny messages, registry dependency) vs full-schema-in-message (self-contained, huge overhead); strict checks (safe, rigid) vs lax (flexible, risky). Closing signal: a versioned, compatibility-enforcing registry with id-based serialization and heavy client caching — the contract layer that lets producers/consumers evolve independently without breaking."),
      C("deep_dive", "Deep dive: governance, formats & operations",
        "Operationally the registry is governance for your event contracts. Compatibility policy per subject: set the default (often BACKWARD) and allow per-subject overrides; wire compatibility CHECKS into CI/CD so an incompatible schema is rejected before deploy, not in production. Formats: Avro is classic (compact, schema-driven, great evolution rules); Protobuf and JSON Schema are also supported — the registry abstracts the format while enforcing evolution. Availability: replicate the registry; because schemas-by-id are immutable, clients cache them indefinitely, so a registry outage only affects encountering NEW ids — still, run it HA. Subject naming/strategy: usually one subject per topic (TopicNameStrategy), but record-based strategies exist for topics carrying multiple event types. Security: control who can register schemas (a breaking or junk schema is a production risk) and audit changes. Migration: evolving past what compatibility allows (a truly breaking change) is handled by a new topic/subject or a versioned event type, with consumers migrated deliberately. Observability: registration rate, compatibility-rejection rate, cache hit rate, and registry availability are the SLOs. The spine holds: a versioned, compatibility-governed registry with id-based serialization, CI-enforced checks, HA, and aggressive client caching."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'Why not put the schema in each message?' too much overhead at scale — carry a small schema id and resolve+cache it from the registry. 'How does it stop a change from breaking consumers?' compatibility checks at registration (backward/forward/full) reject unsafe changes early (wire it into CI). 'Backward vs forward?' backward = consumers upgrade first (new schema reads old data, add optional fields); forward = producers first (old schema reads new data). 'Registry down?' clients cache schemas (immutable by id), so only NEW ids are affected — run it HA. 'A truly breaking change?' new subject/topic or versioned event type, migrate consumers. 'Which formats?' Avro/Protobuf/JSON Schema. 'Who can register?' control + audit it (a bad schema is a prod risk). Each returns to the spine: a versioned, compatibility-enforcing registry + id-based serialization + heavy caching, letting producers/consumers evolve independently."),
    ],
    "A schema registry tests the contract layer for event-driven systems: versioned schemas per subject with enforced compatibility (backward/forward/full) so independently-deployed producers/consumers don't break, plus id-based serialization (small id on the wire, schema fetched+cached) to stay off the hot path. The signal is compatibility-checked evolution + id indirection + HA/caching.",
    [
      G("no_compatibility", "Letting schemas change with no compatibility enforcement.", "Enforce backward/forward/full compatibility at registration (wire into CI).", "Producers change event format with no checks; consumers break."),
      G("schema_in_message", "Embedding the full schema in every message.", "Carry a small schema id; consumers fetch + cache the schema by id.", "Each message includes the whole schema definition."),
      G("registry_down_decode", "Ignoring that the registry is needed to decode new ids.", "Run the registry HA; clients cache immutable schemas + pre-warm.", "No HA/caching; a registry outage stops deserialization of new ids."),
    ],
    0.6, DIAG.schemareg, "Schema registry architecture"),

  // ──────────────────── AUDIT LOG / COMPLIANCE TRAIL ───────────────────────
  TT("sysd_m17", "sysd_m17_t3", 3, "Design an Audit Log / Compliance Trail", "design-audit-log",
    ["case-study", "audit-log", "immutability", "compliance"],
    "For security, compliance, and forensics you must record who did what, when, to which resource — and crucially, the record must be tamper-evident: no one (not even an admin or an attacker) can quietly alter or delete history. How do you build a complete, immutable, queryable trail?",
    "Capture every significant action as an append-only AUDIT EVENT and write it to an IMMUTABLE store (append-only log / WORM), separate from the application database so the app can't alter it. Make it TAMPER-EVIDENT with hash chaining (each entry includes the previous entry's hash, so any change breaks the chain). Capture must be COMPLETE (often via CDC or a mandatory logging layer), and the trail is indexed for who/what/when queries with long retention. Immutability, tamper-evidence, and completeness are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: record an entry for every significant action — WHO (actor), did WHAT (action), to WHICH resource, WHEN (timestamp), and relevant details/before-after — and make the trail QUERYABLE (by actor, resource, time, action) for audits, security investigations, and compliance reporting. Non-functional: IMMUTABILITY (entries cannot be updated or deleted once written), TAMPER-EVIDENCE (any attempt to alter history is detectable), COMPLETENESS (no auditable action is missed — gaps undermine the whole purpose), long RETENTION (often years, per regulation), and integrity/availability. Clarify scope: a compliance/security audit trail (SOC2/HIPAA/financial), distinct from operational/debug logs (which can be lossy). The defining requirement is TRUST IN THE RECORD: an audit log is only useful if you can prove it's complete and unaltered — so the design centers on making the trail append-only and tamper-evident (even against privileged insiders), capturing every action reliably, and keeping it separate from systems whose changes it records so those systems can't rewrite their own history."),
      K("estimation", "Capacity estimation (with numbers)",
        "Assume 100M auditable actions/day -> ~1,160 events/sec (bursty).\n  event ~= a few hundred bytes (actor, action, resource, ts, details, hashes)\n  -> ~tens of GB/day -> retained for YEARS -> tens of TB+ -> tiering + cheap storage\nWrite path must be reliable (no lost events) but isn't extreme throughput.\nQueries: by actor/resource/time -> needs an index; full-text optional.\nTakeaway: moderate write rate but huge cumulative, long-retention store ->\nappend-only + tiering; the hard parts are completeness + tamper-evidence, not scale."),
      C("hld", "High-level design",
        "Auditable actions are CAPTURED — either the application explicitly emits an audit event for each sensitive operation, or changes are captured via CDC/a logging middleware so nothing is missed — and written to an APPEND-ONLY audit store that lives SEPARATELY from the application databases (so a compromised app/admin can't rewrite the trail). Each event records actor, action, resource, timestamp, and details, and is made TAMPER-EVIDENT via HASH CHAINING: each entry includes the cryptographic hash of the previous entry (and its own content), forming a chain where altering any past entry breaks all subsequent hashes — detectable. Entries are INDEXED (by actor/resource/time) for queries, stored on WORM (write-once-read-many) / immutable storage, retained per policy, and access is strictly READ-ONLY for users (only the append path can write). Trace it: user deletes a record -> the app emits an audit event {who, 'delete', resource, ts, before} -> appended to the immutable store with prev-hash -> indexed -> later an auditor queries 'all deletes by user X last month' and can verify the chain is intact. Capture -> append-only tamper-evident store -> query is the shape."),
      K("api", "API design",
        "record({ actor, action, resource, ts, details })   // append-only; no update/delete\n  -> entry { ...fields, prev_hash, hash = H(fields + prev_hash) }\nquery(filter: { actor?, resource?, action?, timeRange }) -> entries\nverify(range) -> chain integrity result   // recompute hashes, detect tampering\n// NO update() or delete() API by design; retention/expiry is policy-controlled"),
      K("data_model", "Data model",
        "audit_event: { id, ts, actor, action, resource, details(before/after),\n               prev_hash, hash }   // hash chains entries -> tamper-evident\nstore:    append-only / WORM (write-once); often a separate, access-controlled system\nindex:    by actor, resource, action, time-range (for investigations/reports)\nretention: time-based (years) + legal hold; tiered (hot recent, cold archive)\n-- no UPDATE/DELETE operations exist on audit entries"),
      C("deep_dive", "Deep dive: immutability & tamper-evidence",
        "The defining property is that the trail can be TRUSTED, which requires both immutability and detectability of tampering. IMMUTABILITY: the store is APPEND-ONLY — there are no update or delete operations on audit entries by design, and ideally it sits on WORM (write-once-read-many) storage or an append-only log so even at the storage layer entries can't be overwritten; access is read-only for everyone except the append path. But immutability of YOUR store isn't enough if a sufficiently privileged attacker could tamper, so add TAMPER-EVIDENCE via HASH CHAINING: each entry stores a cryptographic hash computed over its own content PLUS the previous entry's hash, linking entries into a chain (like a blockchain/Merkle structure). Now if anyone alters or removes a past entry, its hash no longer matches and EVERY subsequent entry's chained hash breaks — so tampering is mathematically DETECTABLE by re-verifying the chain (you can even periodically publish/anchor the latest hash externally so the whole history is pinned). The point isn't to make tampering impossible (storage can be attacked) but to make it IMPOSSIBLE TO HIDE — which is exactly what compliance and forensics require."),
      C("deep_dive", "Deep dive: capture completeness & separation",
        "A trail with gaps is worthless, so two things matter: capturing EVERYTHING and keeping the trail beyond the reach of what it audits. COMPLETENESS: you must record every auditable action reliably. Relying on developers to remember to log each one is fragile (missed actions = blind spots), so prefer systematic capture — a mandatory middleware/aspect that logs sensitive operations, and/or CDC on the underlying data so every data change is captured at the source regardless of code paths. The capture path should be reliable (e.g. write the audit event in the same transaction as the action, or via the transactional-outbox/CDC pattern, so an action can't succeed without its audit entry). SEPARATION OF DUTIES: the audit store is kept SEPARATE from the application and its databases, with its own access controls, so that someone who compromises or administers the application CANNOT also rewrite the history of what they did — the app can append but not modify/delete, and ideally can't even read others' entries. This separation, plus append-only + tamper-evidence, is what makes the trail credible against insider threats — the scenario audits exist for."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "COMPLETENESS is the hardest guarantee — any un-captured action is an invisible gap; systematic capture (middleware/CDC + transactional coupling) beats ad-hoc logging. Storage GROWS forever (long retention) — tier hot/cold and archive to cheap immutable storage, but you generally can't delete within the retention window (and legal holds extend it). Querying huge immutable history needs good indexing (by actor/resource/time) and time-partitioning. Verification cost: re-hashing the whole chain is expensive, so verify incrementally / anchor periodic checkpoints. Write reliability: losing an audit event is a compliance failure, so the write path must be durable (no fire-and-forget that can drop). Trade-offs: explicit app-level capture (precise, context-rich, but easy to miss) vs CDC-based (complete data changes, less business context) — often both; hash chaining (tamper-evident, verification cost) vs plain append-only (simpler, only trusts storage); strict immutability/retention (compliant, costly storage) vs pruning (cheaper, non-compliant). Closing signal: complete capture (middleware/CDC) -> append-only, hash-chained, WORM store separate from the app -> indexed queries + long retention, so the trail is provably complete and unaltered."),
      C("deep_dive", "Deep dive: retention, access control & operations",
        "Operationally the trail must satisfy auditors and resist insiders. Retention & legal hold: keep entries for the regulatory period (often years) on immutable storage; support LEGAL HOLDS that prevent expiry of relevant records during litigation/investigation — and you generally cannot delete within retention (the opposite of GDPR's erasure, a tension handled by minimizing PII in the audit log or pseudonymizing actor ids). Access control: the audit system is read-only to users, write-only (append) from the app, with separate, tightly-controlled admin access — and audit access itself is audited (who read the logs). Tiering: recent entries hot/indexed for active investigations; older entries archived to cheap WORM storage, still queryable (slower). Integrity operations: periodically VERIFY the hash chain and anchor checkpoints (e.g. publish the latest hash to an external/immutable location) so even a full-store compromise can't rewrite history undetected. Export/reporting: produce compliance reports and support investigator queries (timeline of an actor/resource). Observability: capture completeness (gap detection), write success rate, chain-verification status, and storage/retention compliance are the SLOs. The spine holds: complete, append-only, hash-chained, separated, long-retained, access-controlled records — a trail you can prove is whole and untampered."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'How do you stop someone altering history?' append-only + hash chaining (tampering breaks the chain = detectable) + WORM storage + separation from the app. 'How do you ensure nothing is missed?' systematic capture (mandatory middleware/CDC, write audit in the same transaction) rather than ad-hoc logging. 'Why separate from the app DB?' so a compromised/privileged app user can't rewrite their own trail (separation of duties). 'Retention?' years on immutable storage + legal holds; tier hot/cold; can't delete within retention. 'GDPR erasure vs audit immutability?' minimize/pseudonymize PII in the audit log to reconcile them. 'Verify integrity?' re-hash the chain / anchor periodic checkpoints externally. 'Query at scale?' index by actor/resource/time, time-partition. Each returns to the spine: complete capture -> append-only, hash-chained, separated, retained store -> verifiable, queryable trail."),
    ],
    "An audit log tests a trail you can TRUST: complete capture (systematic via middleware/CDC, not ad-hoc), an append-only IMMUTABLE store separate from the app, and TAMPER-EVIDENCE via hash chaining (alteration breaks the chain, detectable), with indexed queries and long retention. The signal is append-only + hash chaining + separation-of-duties + completeness, not just 'write logs to a table'.",
    [
      G("mutable_table", "Storing audit records in a normal, updatable application table.", "Use an append-only, tamper-evident (hash-chained) store separate from the app.", "Audit rows in the app DB that can be UPDATEd/DELETEd."),
      G("no_tamper_evidence", "Append-only but no way to detect tampering by a privileged user.", "Hash-chain entries (+ external checkpoints) so any alteration is detectable.", "Trusts storage alone; no integrity/chain verification."),
      G("incomplete_capture", "Relying on developers to remember to log each action.", "Capture systematically (middleware/CDC, write in the same transaction) for completeness.", "Ad-hoc logging with gaps in coverage."),
    ],
    0.6, DIAG.audit, "Audit log / compliance trail architecture"),

  // ───────────────────────── MULTI-TENANT SAAS ─────────────────────────────
  TT("sysd_m16", "sysd_m16_t6", 6, "Design a Multi-Tenant SaaS Platform", "design-multi-tenant-saas",
    ["case-study", "multi-tenant", "isolation", "saas"],
    "Your SaaS serves thousands of customer organizations (tenants) from shared infrastructure. You must keep each tenant's data strictly isolated (a leak across tenants is catastrophic), stop one heavy tenant from degrading others, and still keep costs low. How do you partition tenants?",
    "Choose a TENANCY model trading isolation against cost: POOLED (shared DB, every row tagged with tenant_id — cheap, dense, isolation by enforced filtering), SILOED (a database per tenant — strong isolation, costly), or a BRIDGE (schema per tenant). A tenant CONTEXT is propagated through every request and EVERY data access is scoped by tenant_id (a single missed filter = cross-tenant leak). Per-tenant QUOTAS/rate limits control noisy neighbors. Isolation models + leak prevention + noisy-neighbor control are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: serve many independent customer organizations (tenants) from one application/platform; isolate each tenant's data and configuration; support per-tenant settings, and ideally per-tenant scaling/customization. Non-functional: strong ISOLATION — data (no tenant can ever see another's data), performance (one tenant's load mustn't degrade others — the NOISY NEIGHBOR problem), and security/compliance (some tenants need stricter guarantees); cost EFFICIENCY (sharing infrastructure is the economic premise of SaaS); and scalability across both many small tenants and a few huge ones. Clarify scope: B2B SaaS multi-tenancy and the tenants' compliance needs. The defining tension is ISOLATION vs COST: the more you isolate tenants (dedicated resources each), the more it costs and the less you exploit sharing; the more you pool them, the cheaper and denser but the more isolation depends on disciplined enforcement rather than physical separation. The cardinal risk is a CROSS-TENANT DATA LEAK (catastrophic for trust/compliance), so every design choice is judged on how reliably it prevents one tenant from accessing another's data while keeping the platform affordable and fair."),
      K("estimation", "Capacity estimation (with numbers)",
        "Assume 10,000 tenants, mostly small + a few huge (power-law).\n  pooled: all in shared DBs sharded by tenant_id -> dense, cheap per tenant\n  siloed: 10,000 databases -> operationally heavy (backups, migrations, connections)\n  -> common pattern: pool small tenants, silo the few large/regulated ones\nNoisy neighbor: one tenant's traffic spike could starve others -> per-tenant quotas.\nLarge-tenant skew: one tenant may be 1000x another -> may need its own shard/DB.\nTakeaway: pooling is cost-efficient at scale but needs strict tenant scoping +\nquotas; siloing suits large/compliance tenants; most platforms mix the two."),
      C("hld", "High-level design",
        "Every request carries a TENANT CONTEXT (resolved from the subdomain, a tenant id in the auth token, or a routing header) that flows through the whole request. The application is shared (stateless services), but DATA is partitioned per the chosen tenancy model: POOLED — one shared database where every table has a tenant_id column and every query is filtered by it (often enforced by row-level security and/or a data-access layer that injects the filter); SILOED — a separate database (or even stack) per tenant, selected by the tenant context; BRIDGE — a separate schema per tenant in a shared database. Cross-cutting controls run per tenant: per-tenant RATE LIMITS/QUOTAS (noisy-neighbor protection), per-tenant configuration, and optionally per-tenant encryption keys. Trace a request: request to acme.app.com -> resolve tenant=acme -> services carry tenant ctx -> data layer scopes every query to tenant_id=acme (pooled) or routes to acme's DB (siloed) -> response. The platform shares compute/code while isolating each tenant's data and resource usage."),
      K("api", "API / tenant scoping",
        "tenant context: from subdomain (acme.app.com) | JWT claim (tid) | header\n  -> set on the request; propagated to every service + data call\nPooled data access (every query scoped):\n  SELECT * FROM orders WHERE tenant_id = :tid AND ...   // NEVER omit tenant_id\n  (enforce via row-level security / a tenant-aware ORM layer, not by hand)\nSiloed: connectionFor(tenant) -> tenant's own DB\nPer-tenant: quotas/rate limits, config, encryption key keyed by tenant"),
      K("data_model", "Data model (by tenancy model)",
        "POOLED:  shared tables, every row has tenant_id (indexed); RLS enforces scoping\nSILOED:  one database per tenant (strong isolation), selected by tenant context\nBRIDGE:  one schema per tenant within a shared database (middle ground)\ntenant registry: tenant_id -> { name, tier, db/shard location, config, keys }\n-- the tenant_id (or DB selection) is the partition key for ALL tenant data"),
      C("deep_dive", "Deep dive: tenancy isolation models",
        "The central decision is the isolation model, a spectrum from shared to dedicated. POOLED (shared everything, tenant_id on every row): maximum density and lowest cost (great for many small tenants), easy to operate (one schema, one migration), but isolation depends entirely on every query being correctly scoped — weaker isolation and a single bug can leak across tenants; also one tenant's data volume/queries share resources (noisy neighbor). SILOED (database/stack per tenant): strong isolation (physical separation — a query simply can't reach another tenant's DB, easy per-tenant backup/restore/compliance, and natural performance isolation), but expensive and operationally heavy (thousands of DBs to provision, migrate, monitor, and connection-manage) — doesn't scale to huge numbers of small tenants. BRIDGE (schema per tenant): a middle ground — more isolation than pooled, more density than siloed, but schema sprawl at scale. The pragmatic answer most SaaS converge on: POOL the many small tenants for cost efficiency, and SILO the few large or compliance-sensitive tenants who justify (and pay for) dedicated isolation — and migrate a tenant from pooled to siloed as it grows. Choose per tenant size, count, and compliance needs."),
      C("deep_dive", "Deep dive: data-leak prevention & noisy neighbors",
        "Two failure modes define operational success. CROSS-TENANT DATA LEAK is the cardinal sin: in a pooled model, isolation rests on EVERY data access being scoped by tenant_id, so a single missing WHERE tenant_id = ... (a developer forgetting it, an injection, a cache key not including the tenant) exposes one tenant's data to another — catastrophic. Defend in DEPTH: don't rely on hand-written filters — enforce scoping at the lowest layer via database ROW-LEVEL SECURITY (the DB rejects rows outside the tenant) and/or a tenant-aware data-access layer/ORM that AUTOMATICALLY injects the tenant filter, include tenant_id in every cache key, and test for leaks; the goal is that omitting the tenant scope is structurally impossible, not just discouraged. (Siloing sidesteps this by physical separation.) NOISY NEIGHBORS: on shared infrastructure, one tenant's heavy load (a huge query, a traffic spike, a runaway job) can degrade others, so enforce per-tenant QUOTAS and RATE LIMITS (the rate-limiter design, keyed by tenant), resource caps, and fair scheduling so each tenant gets its share; a tenant that needs more (or guaranteed) performance can be moved to dedicated resources (siloed). Leak prevention by enforced scoping + noisy-neighbor control by per-tenant quotas are what make shared multi-tenancy safe and fair."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "Cross-tenant data leakage is the highest-severity risk in pooled models — mitigate by enforcing tenant scoping at the DB/data-layer (RLS, auto-injected filters, tenant-keyed caches), not by developer discipline. Noisy neighbors degrade shared tenants — per-tenant quotas/rate limits and resource isolation. Large-tenant SKEW: one giant tenant can dominate a shared DB/shard — give big tenants their own shard/DB (silo them). Operational scale: siloing thousands of tenants explodes DB/migration/connection management. Per-tenant operations (backup, restore, deletion, compliance) are easy when siloed, hard when pooled (must filter by tenant_id). Trade-offs: pooled (cheap, dense, weaker isolation, noisy-neighbor risk, hard per-tenant ops) vs siloed (strong isolation + easy per-tenant ops, expensive + operationally heavy) vs bridge (middle); shared-everything cost efficiency vs dedicated-resource isolation; enforce-scoping-in-code (flexible, leak-prone) vs in-DB (RLS, safer). Closing signal: a tenancy model chosen by tenant size/compliance (commonly pool small + silo large), tenant context propagated everywhere, scoping enforced at the data layer (no leaks), and per-tenant quotas for noisy neighbors."),
      C("deep_dive", "Deep dive: onboarding, migration & operations",
        "Operationally a SaaS platform must onboard, isolate, and manage tenants at scale. Onboarding: provisioning a new tenant is cheap in a pooled model (insert a tenant record) and heavier when siloed (spin up a DB/stack) — automate it. Tier migration: as a small pooled tenant grows large (or needs compliance isolation), MIGRATE it from pooled to its own shard/DB without downtime (dual-write/backfill then cut over) — design for this from the start. Per-tenant operations: backup/restore, data export, and especially DELETION (a tenant leaving, or GDPR) are clean when siloed (drop the DB) and require careful tenant_id-scoped operations when pooled. Compliance & residency: some tenants require data in a specific region or with their own encryption key (per-tenant keys / crypto-isolation) — siloing or per-tenant keys serve this. Schema migrations: pooled = one migration for all (fast but risky — affects everyone at once); siloed = per-tenant migrations (safer staged rollout, more work). Observability per tenant: usage, performance, and cost attributed PER TENANT (for billing and noisy-neighbor detection). Security: tenant isolation testing, and never trust a client-supplied tenant id (derive it from authenticated context). Observability: per-tenant latency/error/usage, cross-tenant-leak tests, and quota breaches are the SLOs. The spine holds: tenant context everywhere, data scoping enforced at the data layer, per-tenant quotas, and a pooled-to-siloed migration path."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'Pooled vs siloed vs bridge?' shared-DB+tenant_id (cheap, dense, weaker isolation) vs DB-per-tenant (strong isolation, costly) vs schema-per-tenant (middle); commonly pool small tenants + silo large/compliance ones. 'How do you prevent cross-tenant leaks?' enforce tenant scoping at the data layer (row-level security, auto-injected filters, tenant-keyed caches) — not hand-written WHEREs. 'Noisy neighbor?' per-tenant quotas/rate limits + resource isolation; silo heavy tenants. 'A huge tenant?' give them a dedicated shard/DB. 'Per-tenant deletion/backup/compliance?' easy siloed (drop DB), scoped operations when pooled; per-tenant keys/region for residency. 'Tenant grows?' migrate pooled -> siloed without downtime. 'Where's tenant id from?' authenticated context (subdomain/JWT), never client-trusted. Each returns to the spine: pick a tenancy model by tenant size/compliance, propagate tenant context, enforce data scoping at the data layer, and control noisy neighbors with per-tenant quotas."),
    ],
    "Multi-tenant SaaS tests the isolation-vs-cost spectrum (pooled shared-DB+tenant_id vs siloed DB-per-tenant vs bridge), preventing cross-tenant data leaks by enforcing tenant scoping at the data layer (RLS/auto-filters, not hand-written WHEREs), and controlling noisy neighbors with per-tenant quotas. The signal is choosing a tenancy model by tenant size/compliance and making missed tenant-scoping structurally impossible.",
    [
      G("no_isolation_model", "Not choosing/justifying a tenancy model (isolation vs cost).", "Pick pooled/siloed/bridge by tenant size + compliance (commonly pool small, silo large).", "No discussion of how tenants are partitioned or isolated."),
      G("leak_by_filter", "Relying on developers to add WHERE tenant_id to every query.", "Enforce scoping at the data layer (row-level security/auto-injected filters, tenant-keyed caches).", "Tenant isolation depends on hand-written filters; one miss leaks."),
      G("noisy_neighbor", "Ignoring that one tenant can degrade others on shared infra.", "Per-tenant quotas/rate limits + resource isolation; silo heavy tenants.", "No per-tenant limits; a heavy tenant starves the rest."),
    ],
    0.6, DIAG.tenant, "Multi-tenant SaaS architecture"),

  // ──────────────────────── GDPR DATA DELETION ─────────────────────────────
  TT("sysd_m17", "sysd_m17_t4", 4, "Design GDPR Data Deletion (Right to be Forgotten)", "design-gdpr-deletion",
    ["case-study", "gdpr", "deletion", "privacy"],
    "A user invokes their right to be forgotten. Their personal data is scattered across your primary databases, caches, search indexes, analytics warehouse, logs, backups, and third-party processors. You must erase it ALL — provably, within a legal deadline. How do you delete data you've spread everywhere?",
    "You can't delete what you can't find, so it starts with a DATA INVENTORY mapping where every piece of personal data lives. A deletion ORCHESTRATOR then fans out erasure to every system that holds it (DBs, caches, search, analytics, third parties) — like a distributed deletion saga — and records completion. BACKUPS are the hard part (you can't surgically edit immutable backups), solved by CRYPTO-SHREDDING (delete the user's encryption key) or delete-on-restore. Completeness, backups, and verifiability are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: on a verified deletion request, erase (or irreversibly anonymize) ALL of a user's personal data wherever it exists — primary databases, caches, search indexes, analytics/data warehouse, message queues/event logs, application logs, file/object storage, BACKUPS, and THIRD-PARTY processors — and provide proof/record of completion. Non-functional: COMPLETENESS (missing any copy is a compliance violation), VERIFIABILITY (you must be able to show it was done), a legal DEADLINE (e.g. within 30 days), reliability (the process must complete even across failures), and it must not break referential integrity or legitimate retained data (some data must be KEPT for legal/financial reasons — anonymize rather than delete). Clarify scope: GDPR/CCPA 'right to erasure'. The defining challenge is that personal data is SCATTERED across many heterogeneous systems you've copied it into (the natural result of caching, indexing, analytics, replication, and backups), so erasure is a DISTRIBUTED problem of FINDING every copy and removing it — and the genuinely hard parts are systems that resist deletion (immutable backups, append-only logs, third parties) and proving completeness."),
      K("estimation", "Capacity estimation (with numbers)",
        "Deletion requests are LOW volume (e.g. hundreds-thousands/day) but each FANS OUT\n  to every system holding PII -> tens of erase operations per request.\nLatency: not interactive -- there's a legal window (e.g. 30 days), so it's an\n   asynchronous, reliable WORKFLOW, not a real-time call.\nBackups: a user's data sits in many historical backups -> can't rewrite them all\n  -> crypto-shredding (one key delete) instead of editing each backup.\nTakeaway: low rate, high fan-out, async with a hard deadline; the cost is\nCOMPLETENESS + verification across many systems + the backup problem, not throughput."),
      C("hld", "High-level design",
        "A verified deletion request enters a deletion ORCHESTRATOR (a durable workflow). Using a DATA INVENTORY / catalog that maps WHERE personal data for a user lives across all systems, the orchestrator FANS OUT erasure commands to each holder: delete/anonymize rows in primary DBs, evict cache entries, remove documents from search indexes, erase/anonymize records in the analytics warehouse, redact logs, and call THIRD-PARTY processors' deletion APIs. Each system has a deletion HANDLER; the orchestrator tracks per-system status, retries failures, and records overall completion (an audit record of the erasure). It's effectively a distributed deletion SAGA: many steps, each must complete, with retries and verification. BACKUPS are handled specially (you can't surgically delete from immutable backups) via crypto-shredding or delete-on-restore. Trace a request: user requests erasure -> verify identity -> orchestrator reads the data map -> emits delete to DB, cache, search, analytics, 3rd-party (async, retried) -> marks each done -> records completion within the deadline -> backups covered by destroying the user's encryption key. Find-everything + orchestrated fan-out erasure + backup strategy + proof is the shape."),
      K("api", "API / workflow",
        "POST /privacy/deletion-requests { userId, verification } -> { requestId, status:'pending' }\nGET  /privacy/deletion-requests/{id} -> { status, perSystem: { db:'done', search:'done', ... } }\nPer-system handler: delete(userId) -> removes/anonymizes that system's PII\norchestrator: for each system in dataInventory(userId): erase + retry + record\n  backups: revoke/destroy user's encryption key (crypto-shred) -> data unreadable"),
      K("data_model", "Data model",
        "deletion_request: id, user_id, status, deadline, per_system_status{...}, completed_at\ndata_inventory:   system -> where/how this user's PII is stored (tables, keys, indices)\nper-user crypto key: user_id -> data encryption key (destroy to crypto-shred backups)\naudit:            record of the erasure (what was deleted/anonymized, when) -- itself PII-minimized\nretained data:    data legally required to keep -> anonymized (not deleted)"),
      C("deep_dive", "Deep dive: finding all the data (the inventory)",
        "The first and hardest problem is that you cannot delete what you cannot FIND, and in a real system personal data has been copied far beyond the primary database — into caches, search indexes, the analytics warehouse, event streams, logs, derived tables, ML feature stores, exports, backups, and third-party tools. So the foundation is a DATA INVENTORY / data map: a catalog of every system and field that holds personal data and how it's keyed to a user, ideally built by TAGGING/classifying PII at design time (data governance) rather than rediscovered per request. Without this map, erasure is guesswork and you WILL miss copies (each a violation). Maintaining it is an ongoing discipline: new pipelines, features, and integrations create new copies, so the inventory must be kept current (data lineage tracking helps — knowing that field X flows into warehouse table Y and cache Z). Designing for deletion from the start — minimizing where PII is copied, centralizing it where possible, and keying everything by a stable user id — makes erasure tractable. The inventory turns 'delete this user' from an impossible scavenger hunt into a defined fan-out over a known set of locations."),
      C("deep_dive", "Deep dive: deletion across systems & the backup problem",
        "With the inventory, deletion is an orchestrated fan-out, but two parts are genuinely hard. CROSS-SYSTEM erasure: the orchestrator must delete/anonymize the user in every holder — synchronous where possible, async (via events/a saga) where systems are eventually consistent — with retries and per-system confirmation, because partial deletion (some systems done, others not) is non-compliant. Some data must be KEPT for legal/financial reasons (e.g. transaction records for tax), so you ANONYMIZE/pseudonymize it (strip identifiers) rather than delete, preserving the non-personal record. THIRD PARTIES that you've shared data with must be told to delete too (via their APIs), and you must track that. The BACKUP problem is the classic gotcha: backups are immutable point-in-time snapshots — you can't (and shouldn't) surgically edit every historical backup to remove one user. The standard solutions: CRYPTO-SHREDDING — encrypt each user's data with a per-user key, and to 'delete' the user, destroy their key, rendering the data (including in all backups) permanently unreadable with a single action; or DELETE-ON-RESTORE — keep a deletion list and re-apply deletions if a backup is ever restored (so restored data doesn't resurrect the user). Crypto-shredding is the elegant answer because one key-deletion covers data everywhere it was encrypted, backups included."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "COMPLETENESS is the binding constraint — a single un-erased copy is a violation, so the data inventory must be accurate and maintained (the #1 risk is unknown copies). BACKUPS resist per-record deletion — solved by crypto-shredding (delete the key) or delete-on-restore, not by editing backups. THIRD PARTIES are outside your control — you can only request deletion and track it. VERIFIABILITY: you must prove erasure (an audit record) — but the audit itself shouldn't store the PII you just deleted (minimize it). RETAINED data (legal holds, financial records) conflicts with deletion — resolve by anonymizing instead of deleting, and by precedence rules (legal retention can override erasure for specific data). The DEADLINE makes it a reliable async workflow with retries, not best-effort. Trade-offs: crypto-shredding (one action covers backups, requires per-user encryption upfront) vs delete-on-restore (no encryption needed, must track + re-apply); delete (gone) vs anonymize (keeps a non-personal record for legal needs); centralized PII (easy to delete, single point) vs scattered (realistic, hard to erase). Closing signal: a maintained data inventory -> orchestrated, retried, verified fan-out erasure across all systems + third parties -> crypto-shredding for backups -> recorded completion within the deadline, anonymizing legally-retained data."),
      C("deep_dive", "Deep dive: verification, anonymization & operations",
        "Operationally the process must be reliable, provable, and reconciled with retention. Reliability: the orchestrator is a durable workflow (saga) — it persists per-system status and retries failed deletions until every system confirms, so a crash mid-deletion resumes rather than leaving a partial erasure; a dead-letter/alert path surfaces systems that can't complete (e.g. a down third party) before the deadline. Verification: record what was deleted/anonymized and when (proof of compliance), and ideally re-scan to confirm no PII remains for that user — without the verification record itself becoming a new store of the deleted PII (store only the fact + minimal identifiers). Anonymization vs deletion: for data you must legally keep, irreversibly strip personal identifiers (so the record is no longer personal data) instead of deleting — and ensure anonymization is truly irreversible (no re-identification via joins). Deadlines & SLAs: track each request against its legal deadline; alert on at-risk requests. Re-creation guard: ensure deleted users aren't re-imported from a stale backup or pipeline (delete-on-restore list + pipeline checks). Crypto-shred key management: per-user keys must be securely stored and destroyably deletable. Observability: deletion completeness per request, per-system success, deadline adherence, and leftover-PII scans are the SLOs. The spine holds: a durable, verified, retried erasure workflow over a maintained data map, crypto-shredding backups, anonymizing retained data."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'How do you find all the user's data?' a maintained data inventory/map of where PII lives (tag PII at design time) — you can't delete what you can't find. 'How do you delete from immutable backups?' crypto-shredding (per-user encryption key; destroy it -> data unreadable everywhere) or delete-on-restore. 'Partial deletion?' it's a saga — retry each system until all confirm; non-compliant if incomplete. 'Data you must legally keep?' anonymize/pseudonymize instead of deleting (it's no longer personal data). 'Third parties?' call their deletion APIs and track completion. 'Prove it was done?' an audit record of the erasure (PII-minimized). 'Deleted user resurrected from a backup restore?' delete-on-restore list / pipeline checks. 'Deadline?' async durable workflow tracked against the legal window. Each returns to the spine: find every copy (inventory) -> orchestrated, retried, verified erasure across all systems + third parties -> crypto-shred backups -> record completion, anonymizing retained data."),
    ],
    "GDPR deletion tests erasing scattered personal data completely and provably: a maintained DATA INVENTORY (you can't delete what you can't find), an orchestrated retried fan-out (a deletion saga) across all systems + third parties, CRYPTO-SHREDDING for immutable backups, anonymizing legally-retained data, and a verifiable completion record within a deadline. The signal is the inventory + the backup problem (crypto-shred) + completeness/verification.",
    [
      G("delete_primary_only", "Deleting only from the primary DB, forgetting caches/search/analytics/backups/3rd-parties.", "Use a data inventory + orchestrated fan-out to erase every copy everywhere.", "Deletion is a single DELETE on the main database."),
      G("backups_ignored", "No plan for immutable backups (data persists / resurrects on restore).", "Crypto-shred (destroy the per-user key) or delete-on-restore so backups are covered.", "Ignores backups, or proposes editing every backup."),
      G("no_completeness_proof", "No data map / no verification of completeness.", "Maintain a PII inventory and record + verify erasure per system (proof within the deadline).", "No inventory; can't prove all copies were erased."),
    ],
    0.7, DIAG.gdpr, "GDPR data deletion architecture"),

  // ─────────────────────────────── OTP / 2FA ───────────────────────────────
  TT("sysd_m14", "sysd_m14_t3", 3, "Design an OTP / 2FA Service", "design-otp-service",
    ["case-study", "otp", "2fa", "security"],
    "As a second authentication factor, users enter a one-time code — from an SMS, an email, or an authenticator app. The code must be unguessable, usable exactly once, expire fast, and resist brute-force and abuse. How do you generate, deliver, and verify one-time passwords securely at scale?",
    "Two families: DELIVERED OTP — generate a random code, store it HASHED with a short TTL keyed to the user, send it via SMS/email (the notification system), and verify by comparing within the window; and TOTP — a shared secret + the current time window generate the same code on the user's authenticator app and your server independently, with NO delivery needed. Either way: single-use, short-lived, RATE-LIMITED (generation and verification), stored hashed, constant-time compared. Generation/delivery/verification security is the substance.",
    [
      C("requirements", "Requirements",
        "Functional: generate a one-time code as a SECOND factor, deliver it (SMS/email) or have the user's authenticator app produce it (TOTP), and VERIFY a submitted code; support resend and (ideally) backup codes. Non-functional: SECURITY above all — codes must be unguessable, SINGLE-USE (can't be replayed), short-lived (expire in minutes), and resistant to BRUTE-FORCE and abuse (rate-limited); plus reliable delivery, low latency, and scale. Clarify scope: OTP as a 2FA/MFA factor (and the channel — SMS/email vs authenticator-app TOTP, which have very different security properties). The defining concern is SECURITY under adversarial conditions: an attacker may try to brute-force codes, intercept delivery (SMS is interceptable / SIM-swappable), or replay a code — so the design must make codes hard to guess (enough entropy + short TTL), impossible to reuse (single-use), and expensive to attack (strict rate limiting on both generation and verification), while remaining usable. It's less about throughput and more about getting the security properties right."),
      K("estimation", "Capacity estimation (with numbers)",
        "OTP requests track logins/sensitive actions: e.g. 10M logins/day -> ~115/sec avg.\n  6-digit code = 1,000,000 possibilities -> with a 5-attempt limit, guess odds ~5e-6\n  -> entropy is fine ONLY because verification is rate-limited (else brute-forceable)\nStorage: one OTP record per pending verification (hashed code + TTL) -> tiny, in Redis.\nTOTP: just a per-user secret stored once; no per-request storage or delivery.\nTakeaway: low data/throughput; security comes from short TTL + single-use +\nstrict rate limits, NOT from code length alone (6 digits is weak without limits)."),
      C("hld", "High-level design",
        "On an OTP request, the service either (DELIVERED) GENERATES a random numeric code, stores it HASHED with a short TTL keyed by user/session (e.g. in Redis), and sends it via the notification system (SMS/email gateway); or (TOTP) does nothing to deliver — the user's authenticator app and the server both derive the current code from a SHARED SECRET (established at enrollment) + the current time window. On VERIFY, the service looks up the user's pending OTP (or computes the expected TOTP for the current/adjacent time windows), compares (constant-time) the submitted code, and on success marks it USED (single-use) and authenticates; on failure it increments an attempt counter and applies RATE LIMITING/lockout. Trace delivered OTP: request -> code=4729 -> store hash(4729) ttl=300s for user U -> SMS '4729' -> user submits 4729 -> compare to stored hash, within TTL, attempts<limit -> success, invalidate. Trace TOTP: enroll -> shared secret -> app shows code for this 30s window -> server computes the same from the secret+time -> match. Generation/storage + delivery (or TOTP) + verified single-use comparison under rate limits is the shape."),
      K("api", "API design",
        "POST /otp/request { userId, channel: 'sms'|'email'|'totp' } -> 200 (sent / use app)\n  delivered: code = random6(); store HASH(code) with TTL=300s; send via gateway\nPOST /otp/verify { userId, code } -> { verified: bool }\n  check: within TTL, attempts < limit, constant-time compare; on success mark used\nTOTP enroll: GET /otp/totp/secret -> shared secret (QR) ; verify computes TOTP(secret, now)\nRate limits on BOTH request (resend abuse) and verify (brute force)"),
      K("data_model", "Data model",
        "delivered OTP (Redis):  otp:{userId} -> { hash(code), expires_at, attempts }  TTL\nTOTP:  user_id -> shared_secret (stored encrypted, set once at enrollment)\nbackup codes: user_id -> [ hash(code) ] (single-use recovery codes)\nrate limits:  per-user/IP counters on request (resend) and verify (attempts)\n-- codes stored HASHED, never plaintext; single-use flag/deletion on success"),
      C("deep_dive", "Deep dive: TOTP vs delivered OTP",
        "The two approaches differ fundamentally. DELIVERED OTP: the server generates a random code and SENDS it over a channel (SMS/email), then the user reads and submits it. Pros: no app needed, familiar. Cons: it depends on an external channel that can be intercepted — SMS is notoriously weak (SIM-swap attacks, SS7 interception), and delivery adds latency/cost and can fail; the code also lives transiently on the server (store it hashed, short TTL). TOTP (Time-based One-Time Password, RFC 6238): at enrollment the server and the user's authenticator app share a SECRET; thereafter BOTH independently compute the same code from that secret + the current time window (e.g. a new 6-digit code every 30s) using HMAC — so NO code is transmitted at all (nothing to intercept), no delivery channel or cost, and it works offline. The server verifies by computing the expected code for the current window (and usually one adjacent window to tolerate clock skew) and comparing. TOTP is the stronger, standard choice for app-based 2FA precisely because it removes the vulnerable delivery channel; delivered OTP (especially SMS) is more convenient but weaker. Knowing this trade-off — and that SMS OTP is the least secure factor — is the heart of the topic."),
      C("deep_dive", "Deep dive: securing generation & verification",
        "Several disciplines make OTP actually secure. SINGLE-USE: once a code verifies, immediately INVALIDATE it (delete/mark used) so it can't be replayed; a code is good for exactly one successful verification. SHORT TTL / time window: delivered codes expire in a few minutes, and TOTP codes are valid only for their ~30s window (plus a small skew allowance) — minimizing the attack window. RATE LIMITING is essential and applies to BOTH directions: on VERIFY, limit attempts per code/user (e.g. 5) then lock out, because a 6-digit code is only 1,000,000 possibilities — trivially brute-forceable without a limit (this is THE reason short codes are safe: not entropy, but capped attempts); on REQUEST, limit resends to prevent SMS-bombing/abuse and cost. STORAGE: never store the code in plaintext — store a HASH (so a DB leak doesn't reveal active codes), and the TOTP secret encrypted. CONSTANT-TIME comparison avoids timing side-channels. BINDING: tie the OTP to the specific user/session/action so a code for one context can't be used for another. Generation must use a cryptographically secure RNG (delivered) or proper HMAC (TOTP). Single-use + short TTL + strict rate limits + hashed storage + constant-time compare are what turn a guessable 6-digit number into a secure second factor."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "BRUTE FORCE is the primary threat — a 6-digit code is weak by entropy, so VERIFY rate limiting / lockout is mandatory (the security rests on it, not code length). SMS delivery is the weak link — interceptable (SIM-swap/SS7), costly, and can fail/lag — prefer TOTP or app push for sensitive accounts; SMS-bombing requires REQUEST rate limits. Replay is prevented by single-use + short TTL. TOTP clock skew requires accepting adjacent time windows (small skew tolerance), trading a slightly larger window for usability. Delivery reliability/cost scales with volume (the notification-system concerns). Account lockout from too-strict limits hurts UX (denial of service on the user) — balance attempt limits with backup codes/recovery. Trade-offs: TOTP (no delivery, no interception, offline, needs an app + secret enrollment) vs delivered OTP (no app, convenient, but interceptable channel + cost); SMS (ubiquitous, least secure) vs authenticator app vs push; strict rate limits (secure, lockout risk) vs lenient (usable, brute-force risk); short TTL (secure, more resends) vs longer (convenient, larger window). Closing signal: single-use, short-TTL, rate-limited (request + verify), hashed-stored, constant-time-compared codes — preferring TOTP over interceptable SMS for strong 2FA."),
      C("deep_dive", "Deep dive: delivery, recovery & operations",
        "Operationally OTP must be secure, usable, and reliable. Delivery: delivered OTP rides the notification system (SMS/email gateways) with its retries/provider-failover — but treat SMS as the weakest channel and steer sensitive flows to TOTP or push-based approval. Recovery & lockout: users lose phones and get locked out, so provide BACKUP CODES (single-use recovery codes, stored hashed) and a secure account-recovery path — without these, strict rate limiting becomes a self-inflicted denial of service; balance attempt limits (security) against lockout (UX), with progressive backoff. Enrollment: TOTP enrollment must securely share the secret (QR code over an authenticated session) and confirm with a test code; the secret is stored encrypted. Anti-abuse: rate-limit OTP REQUESTS per user/IP to prevent SMS-bombing and cost blowups, and watch for credential-stuffing patterns. Phishing resistance: note that OTPs (even TOTP) are phishable (a user can be tricked into entering a code on a fake site) — for high security, FIDO2/WebAuthn (hardware keys/passkeys) are phishing-resistant alternatives to mention. Observability: verification success/failure rates, lockouts, delivery success (per channel), and brute-force attempt patterns are the SLOs. The spine holds: securely generated, single-use, short-TTL, rate-limited, hashed codes delivered reliably (or TOTP), with backup-code recovery and abuse controls."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'Why is a 6-digit code safe?' it isn't by entropy — VERIFY rate limiting/lockout (e.g. 5 attempts) is what prevents brute force. 'TOTP vs SMS OTP?' TOTP shares a secret and computes codes from time on the device (nothing transmitted, no interception, offline) — stronger; SMS is convenient but interceptable (SIM-swap). 'Prevent replay?' single-use (invalidate on success) + short TTL. 'Store the code?' hashed, never plaintext; constant-time compare. 'SMS-bombing/abuse?' rate-limit OTP requests too. 'Clock skew with TOTP?' accept adjacent time windows. 'User loses their phone?' backup codes + secure recovery (don't let strict limits become a permanent lockout). 'Phishing-resistant option?' FIDO2/WebAuthn (passkeys). Each returns to the spine: single-use, short-TTL, rate-limited (request + verify), hashed, constant-time-compared codes — TOTP preferred over interceptable SMS."),
    ],
    "An OTP/2FA service tests secure one-time codes: single-use + short TTL + strict rate limiting (on BOTH generation and verification, since a 6-digit code is brute-forceable without limits) + hashed storage + constant-time compare, and the TOTP-vs-delivered-OTP trade-off (TOTP transmits nothing and beats interceptable SMS). The signal is that security comes from rate limits/single-use/short-TTL, not code length, and preferring TOTP.",
    [
      G("no_rate_limit", "Relying on a 6-digit code's entropy without limiting verification attempts.", "Strictly rate-limit verification (lock out after N attempts) — that's what stops brute force.", "No attempt limit; a 6-digit code is brute-forceable in ~1M tries."),
      G("plaintext_reusable", "Storing codes in plaintext and/or allowing reuse.", "Store codes hashed, make them single-use (invalidate on success) and short-TTL.", "Code stored plaintext or accepted more than once / no expiry."),
      G("sms_assumed_secure", "Treating SMS OTP as strong security.", "Prefer TOTP (no transmitted code, no interception); treat SMS as the weakest factor.", "SMS OTP presented as a robust second factor with no caveat."),
    ],
    0.5, DIAG.otp, "OTP / 2FA service architecture"),
];

// ── 3 exercises per topic ────────────────────────────────────────────────────
const xpFor = (l) => (l === "warmup" ? 5 : l === "easy" ? 10 : l === "medium" ? 15 : 20);
const diffFor = (l) => (l === "warmup" ? 0.1 : l === "easy" ? 0.2 : l === "medium" ? 0.4 : 0.6);
function pm(moduleId, o) {
  return { trackKey: TRACK_KEY, moduleId, topicId: o.topicId, exerciseId: o.exerciseId,
    position: o.position, level: o.level, type: "pattern_match", title: o.title, scenario: o.scenario,
    instructions: "Pick the best answer.", starterCode: "", expectedSolution: o.correct,
    blanks: [{ options: o.options }], testCases: [{ type: "pattern_match", correct: o.correct, explanation: o.explanation }],
    hints: [], xpReward: xpFor(o.level), difficulty: diffFor(o.level) };
}

